   112→// ReadPluginManifestFromFS reads the plugin manifest from the provided plugins.FS.
   113→// If the manifest is not found, it will return an error wrapping ErrSignatureTypeUnsigned.
   114→func (s *Signature) ReadPluginManifestFromFS(ctx context.Context, pfs plugins.FS) (*PluginManifest, error) {
   115→	f, err := pfs.Open("MANIFEST.txt")
   116→	if err != nil {
   117→		if errors.Is(err, plugins.ErrFileNotExist) {
   118→			return nil, fmt.Errorf("%w: could not find a MANIFEST.txt", ErrSignatureTypeUnsigned)
   119→		}
   120→		return nil, fmt.Errorf("could not open MANIFEST.txt: %w", err)
   121→	}
   122→	defer func() {
   123→		if f == nil {
   124→			return
   125→		}
   126→		if err = f.Close(); err != nil {
   127→			s.log.Warn("Failed to close plugin MANIFEST file", "error", err)
   128→		}
   129→	}()
   130→
   131→	byteValue, err := io.ReadAll(f)
   132→	if err != nil || len(byteValue) < 10 {
   133→		return nil, fmt.Errorf("%w: MANIFEST.txt is invalid", ErrSignatureTypeUnsigned)
   134→	}
   135→
   136→	manifest, err := s.readPluginManifest(ctx, byteValue)
   137→	if err != nil {
   138→		return nil, err
   139→	}
   140→	return manifest, nil
   141→}
