    90→func setDefaultNavURL(p *plugins.Plugin) {
    91→	// slugify pages
    92→	for _, include := range p.Includes {
    93→		if include.Slug == "" {
    94→			include.Slug = slugify.Slugify(include.Name)
    95→		}
    96→
    97→		if !include.DefaultNav {
    98→			continue
    99→		}
   100→
   101→		if include.Type == "page" {
   102→			p.DefaultNavURL = path.Join("/plugins/", p.ID, "/page/", include.Slug)
   103→		}
   104→		if include.Type == "dashboard" {
   105→			dboardURL := include.DashboardURLPath()
   106→			if dboardURL == "" {
   107→				p.Logger().Warn("Included dashboard is missing a UID field")
   108→				continue
   109→			}
   110→
   111→			p.DefaultNavURL = dboardURL
   112→		}
   113→	}
   114→}
